func (v *ValueSource) validate() error {
	if v == nil {
		return fmt.Errorf("type %T is nil", v)
	}
	var fields []string
	if v.Header != nil {
		fields = append(fields, "header")
	}
	if v.HeaderParam != nil {
		fields = append(fields, "header_param")
	}
	if v.Query != nil {
		fields = append(fields, "query")
	}
	if v.JSONPath != nil {
		fields = append(fields, "json_path")
	}
	if v.RawBody != nil {
		fields = append(fields, "raw_body")
	}
	if v.Method != nil {
		fields = append(fields, "method")
	}
	if v.Path != nil {
		fields = append(fields, "path")
	}
	if len(fields) == 0 {
		if v.Source != "" {
			return fmt.Errorf("type %T defines a discriminant set to %q but the field is not set", v, v.Source)
		}
		return fmt.Errorf("type %T is empty", v)
	}
	if len(fields) > 1 {
		return fmt.Errorf("type %T defines values for %s, but only one value is allowed", v, fields)
	}
	if v.Source != "" {
		field := fields[0]
		if v.Source != field {
			return fmt.Errorf(
				"type %T defines a discriminant set to %q, but it does not match the %T field; either remove or update the discriminant to match",
				v,
				v.Source,
				v,
			)
		}
	}
	return nil
}

